import React, { useState } from "react";
import {
  Mail,
  Phone,
  MapPin,
  Clock,
  BookOpen,
  Calendar,
  Users,
} from "lucide-react";
import { FaPaperPlane } from "react-icons/fa";

const EnquiryPage = () => {
  const [formData, setFormData] = useState({
    firstName: "",
    lastName: "",
    email: "",
    phone: "",
    studentName: "",
    grade: "",
    dateOfBirth: "",
    previousSchool: "",
    enquiryType: "admission",
    message: "",
  });

  const [submitted, setSubmitted] = useState(false);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    setSubmitted(true);
    setTimeout(() => {
      setSubmitted(false);
      setFormData({
        firstName: "",
        lastName: "",
        email: "",
        phone: "",
        studentName: "",
        grade: "",
        dateOfBirth: "",
        previousSchool: "",
        enquiryType: "admission",
        message: "",
      });
    }, 3000);
  };

  return (
    <div className="min-h-screen bg-green-950">
      {/* Hero Banner – school building image + green overlay */}
      <div
        className="relative w-full h-52 md:h-72 overflow-hidden"
        style={{
          backgroundImage: `url('data:image/jpeg;base64,')`,
          backgroundSize: "cover",
          backgroundPosition: "center",
        }}
      >
        {/* Green overlay */}
        <div className="absolute inset-0 bg-green-950/80"></div>

        {/* Content */}
        <div className="relative z-10 h-full flex flex-col items-center justify-center px-4">
          <h1 className="text-4xl md:text-5xl font-bold text-white text-center mb-3">
            Admission Enquiry
          </h1>
          <div className="w-24 h-1 bg-green-400 mb-4"></div>
          <p className="text-white/80 text-center text-base md:text-lg max-w-2xl mx-auto">
            Take the first step towards your child's bright future. We're here
            to answer all your questions.
          </p>
        </div>
      </div>

      <div className="container mx-auto px-4 py-14">
        <div className="grid lg:grid-cols-3 gap-8 max-w-7xl mx-auto">
          {/* Left Column */}
          <div className="lg:col-span-1 space-y-6">
            {/* Contact Info */}
            <div className="bg-green-900/60 border border-green-500/30 p-8">
              <h3 className="text-2xl font-bold text-green-400 mb-6">
                Get In Touch
              </h3>
              <div className="space-y-5">
                {[
                  {
                    icon: <Phone className="w-5 h-5 text-green-900" />,
                    title: "Phone",
                    lines: ["+91 94714 04548", "+91 70501 54850"],
                  },
                  {
                    icon: <Mail className="w-5 h-5 text-green-900" />,
                    title: "Email",
                    lines: [
                      "admissions@thawecentral.edu",
                      "info@thawecentral.edu",
                    ],
                  },
                  {
                    icon: <MapPin className="w-5 h-5 text-green-900" />,
                    title: "Address",
                    lines: [
                      "AT- BEDUTOLA, PO- THAWE,",
                      "DIST- GOPALGANJ, 841440",
                    ],
                  },
                  {
                    icon: <Clock className="w-5 h-5 text-green-900" />,
                    title: "Office Hours",
                    lines: ["Mon - Sat: 7:00 AM - 4:00 PM", "Sunday: Closed"],
                  },
                ].map(({ icon, title, lines }) => (
                  <div key={title} className="flex items-start gap-4">
                    <div className="w-10 h-10 bg-green-400 flex items-center justify-center flex-shrink-0">
                      {icon}
                    </div>
                    <div>
                      <p className="font-semibold text-green-300 text-sm uppercase tracking-wide">
                        {title}
                      </p>
                      {lines.map((l, i) => (
                        <p key={i} className="text-white/80 text-sm">
                          {l}
                        </p>
                      ))}
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* Why Choose Us */}
            <div className="bg-green-500/15 border border-green-500/30 p-8">
              <h3 className="text-2xl font-bold text-green-400 mb-6">
                Why Choose Us?
              </h3>
              <div className="space-y-5">
                {[
                  {
                    icon: <BookOpen className="w-5 h-5" />,
                    title: "Quality Education",
                    desc: "Experienced faculty with modern teaching methods",
                  },
                  {
                    icon: <Users className="w-5 h-5" />,
                    title: "Small Class Sizes",
                    desc: "Individual attention for every student",
                  },
                  {
                    icon: <Calendar className="w-5 h-5" />,
                    title: "CBSE Pattern",
                    desc: "Affiliated with Bihar Board, English Medium",
                  },
                ].map(({ icon, title, desc }) => (
                  <div key={title} className="flex items-start gap-3">
                    <div className="text-green-400 mt-0.5 flex-shrink-0">
                      {icon}
                    </div>
                    <div>
                      <p className="font-semibold text-white">{title}</p>
                      <p className="text-white/60 text-sm">{desc}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* Right Column – Form */}
          <div className="lg:col-span-2">
            <div className="bg-green-900/50 border border-green-500/30 shadow-2xl overflow-hidden">
              <div className="p-8 md:p-12">
                <div className="text-center mb-10">
                  <h3 className="text-3xl md:text-4xl font-extrabold text-white mb-2">
                    Send an <span className="text-green-400">Enquiry</span>
                  </h3>
                  <p className="text-white/50 text-sm max-w-md mx-auto">
                    Whether you have a request, a query, or want to know about
                    THAWE CENTRAL SCHOOL, use the form below.
                  </p>
                </div>

                {submitted && (
                  <div className="bg-green-500/20 border border-green-500 p-4 mb-6">
                    <p className="text-green-400 font-semibold text-center">
                      ✓ Thank you! Your enquiry has been submitted. We'll
                      contact you soon.
                    </p>
                  </div>
                )}

                <div className="space-y-5">
                  {/* Enquiry Type */}
                  <div className="flex flex-col gap-2">
                    <label className="text-xs font-bold text-green-400 uppercase tracking-wider">
                      Enquiry Type *
                    </label>
                    <select
                      name="enquiryType"
                      value={formData.enquiryType}
                      onChange={handleChange}
                      className="custom-input"
                    >
                      <option value="admission">New Admission</option>
                      <option value="transfer">School Transfer</option>
                      <option value="general">General Information</option>
                      <option value="visit">School Visit</option>
                    </select>
                  </div>

                  {/* Name */}
                  <div className="grid md:grid-cols-2 gap-5">
                    <div className="flex flex-col gap-2">
                      <label className="text-xs font-bold text-green-400 uppercase tracking-wider">
                        First Name *
                      </label>
                      <input
                        type="text"
                        name="firstName"
                        value={formData.firstName}
                        onChange={handleChange}
                        placeholder="First name"
                        className="custom-input"
                      />
                    </div>
                    <div className="flex flex-col gap-2">
                      <label className="text-xs font-bold text-green-400 uppercase tracking-wider">
                        Last Name *
                      </label>
                      <input
                        type="text"
                        name="lastName"
                        value={formData.lastName}
                        onChange={handleChange}
                        placeholder="Last name"
                        className="custom-input"
                      />
                    </div>
                  </div>

                  {/* Phone & Email */}
                  <div className="grid md:grid-cols-2 gap-5">
                    <div className="flex flex-col gap-2">
                      <label className="text-xs font-bold text-green-400 uppercase tracking-wider">
                        Mobile No *
                      </label>
                      <input
                        type="tel"
                        name="phone"
                        value={formData.phone}
                        onChange={handleChange}
                        placeholder="+91 00000 00000"
                        className="custom-input"
                      />
                    </div>
                    <div className="flex flex-col gap-2">
                      <label className="text-xs font-bold text-green-400 uppercase tracking-wider">
                        Email *
                      </label>
                      <input
                        type="email"
                        name="email"
                        value={formData.email}
                        onChange={handleChange}
                        placeholder="example@mail.com"
                        className="custom-input"
                      />
                    </div>
                  </div>

                  {/* Student Name & Grade */}
                  <div className="grid md:grid-cols-2 gap-5">
                    <div className="flex flex-col gap-2">
                      <label className="text-xs font-bold text-green-400 uppercase tracking-wider">
                        Student Name *
                      </label>
                      <input
                        type="text"
                        name="studentName"
                        value={formData.studentName}
                        onChange={handleChange}
                        placeholder="Student's full name"
                        className="custom-input"
                      />
                    </div>
                    <div className="flex flex-col gap-2">
                      <label className="text-xs font-bold text-green-400 uppercase tracking-wider">
                        Grade / Class *
                      </label>
                      <select
                        name="grade"
                        value={formData.grade}
                        onChange={handleChange}
                        className="custom-input"
                      >
                        <option value="">Select Grade</option>
                        <option value="nursery">Nursery</option>
                        <option value="lkg">LKG</option>
                        <option value="ukg">UKG</option>
                        {[...Array(8)].map((_, i) => (
                          <option key={i + 1} value={i + 1}>
                            Class {i + 1}
                          </option>
                        ))}
                      </select>
                    </div>
                  </div>

                  {/* DOB & Previous School */}
                  <div className="grid md:grid-cols-2 gap-5">
                    <div className="flex flex-col gap-2">
                      <label className="text-xs font-bold text-green-400 uppercase tracking-wider">
                        Date of Birth *
                      </label>
                      <input
                        type="date"
                        name="dateOfBirth"
                        value={formData.dateOfBirth}
                        onChange={handleChange}
                        className="custom-input"
                      />
                    </div>
                    <div className="flex flex-col gap-2">
                      <label className="text-xs font-bold text-green-400 uppercase tracking-wider">
                        Previous School
                      </label>
                      <input
                        type="text"
                        name="previousSchool"
                        value={formData.previousSchool}
                        onChange={handleChange}
                        placeholder="Previous school name"
                        className="custom-input"
                      />
                    </div>
                  </div>

                  {/* Message */}
                  <div className="flex flex-col gap-2">
                    <label className="text-xs font-bold text-green-400 uppercase tracking-wider">
                      Message *
                    </label>
                    <textarea
                      rows={4}
                      name="message"
                      value={formData.message}
                      onChange={handleChange}
                      placeholder="Any specific questions or requirements..."
                      className="custom-input resize-none"
                    />
                  </div>

                  {/* Submit */}
                  <div className="pt-2">
                    <button
                      onClick={handleSubmit}
                      className="w-full bg-green-500 hover:bg-green-400 text-black font-extrabold py-4 flex items-center justify-center gap-3 transition-all text-base hover:-translate-y-0.5 active:scale-[0.98] shadow-lg shadow-green-500/20"
                    >
                      SUBMIT MESSAGE <FaPaperPlane className="text-sm" />
                    </button>
                  </div>
                </div>
              </div>
            </div>

            {/* Admission Process */}
            <div className="mt-6 bg-green-500/10 border border-green-500/25 p-8">
              <h3 className="text-xl font-bold text-white mb-6">
                Admission Process
              </h3>
              <div className="grid md:grid-cols-4 gap-6">
                {[
                  {
                    num: 1,
                    title: "Submit Enquiry",
                    desc: "Fill the form above",
                  },
                  { num: 2, title: "School Visit", desc: "Tour our campus" },
                  {
                    num: 3,
                    title: "Documentation",
                    desc: "Submit required docs",
                  },
                  { num: 4, title: "Welcome!", desc: "Join our family" },
                ].map((step) => (
                  <div key={step.num} className="text-center">
                    <div className="w-14 h-14 bg-green-500 flex items-center justify-center text-black font-bold text-xl mx-auto mb-3">
                      {step.num}
                    </div>
                    <p className="font-semibold text-white text-sm">
                      {step.title}
                    </p>
                    <p className="text-white/50 text-xs mt-1">{step.desc}</p>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>

      <style jsx>{`
        .custom-input {
          width: 100%;
          padding: 13px 16px;
          background: rgba(0, 0, 0, 0.3);
          border: 1px solid rgba(74, 222, 128, 0.25);
          border-radius: 0;
          color: #fff;
          font-size: 14px;
          transition: all 0.25s ease;
        }
        .custom-input::placeholder {
          color: rgba(255, 255, 255, 0.35);
        }
        .custom-input option {
          background: #052e16;
          color: #fff;
        }
        .custom-input:focus {
          outline: none;
          border-color: rgba(74, 222, 128, 0.7);
          box-shadow: 0 0 0 3px rgba(74, 222, 128, 0.1);
          background: rgba(0, 0, 0, 0.45);
        }
      `}</style>
    </div>
  );
};

export default EnquiryPage;
